export default function HomePage() {
  return (
    <div>
      <h1>Style Busters — ¡Rompe el estilo, no tu billetera!</h1>

      <div className="grid">
        {products.map((p) => (
          <ProductCard key={p.id} product={p} />
        ))}
      </div>
    </div>
  );
}
